mapper.select:
SELECT id, code, title, content, source, DATE_FORMAT(publish_date, '%Y-%m-%d %H:%i') as publish_date, news_type, sentiment_score, event_tag, url FROM stock_news WHERE code = #{code}
AND news_type = #{newsType}
AND event_tag LIKE CONCAT(#{eventTag}, '%')
ORDER BY publish_date DESC LIMIT #{limit}
